UPDATE member SET memberPhone1 = #{memberPhone1}, memberPhone2 = #{memberPhone2}, memberPhone3 = #{memberPhone3}, memberNickname = #{memberNickname}, memberEmail1 = #{memberEmail1}, memberEmail2 = #{memberEmail2}, memberZip1 = #{memberZip1}, memberZip2 = #{memberZip2}, memberZip3 = #{memberZip3}, memberUpdated = CURRENT_TIMESTAMP
, memberImage = #{memberImage}
, memberImage = NULL
WHERE memberId = #{memberId}

UPDATE member
SET memberPw = #{newPwd}
WHERE memberId = #{memberId}

mapper.select:
SELECT memberId 
FROM member
WHERE memberName = #{memberName}
  AND memberPhone1 = #{memberPhone1}
  AND memberPhone2 = #{memberPhone2}
  AND memberPhone3 = #{memberPhone3}

SELECT memberId 
FROM member
WHERE memberName = #{memberName}
  AND memberId = #{memberId}
  AND memberEmail1 = #{memberEmail1}
